  console.log(`${new Date().toISOString()} - ${req.method} ${req.url} - IP: ${req.ip}`);
  next();
});

// Simple rate limiting without express-rate-limit package
const requestCounts = new Map();
const WINDOW_MS = 15 * 60 * 1000; // 15 minutes
const MAX_REQUESTS = 100;

app.use((req, res, next) => {
  const clientIP = req.ip;
  const now = Date.now();

  // Clean old entries
  for (const [ip, data] of requestCounts) {
    if (now - data.timestamp > WINDOW_MS) {
      requestCounts.delete(ip);
    }
  }

  // Check rate limit
  const requestData = requestCounts.get(clientIP) || { count: 0, timestamp: now };

  if (now - requestData.timestamp < WINDOW_MS) {
    if (requestData.count >= MAX_REQUESTS) {
      return res.status(429).json({ 
        error: 'Too many requests from this IP, please try again later.',
        timestamp: new Date().toISOString() 
      });
    }
    requestData.count++;
  } else {
    requestData.count = 1;
    requestData.timestamp = now;
  }

  requestCounts.set(clientIP, requestData);
  next();
});

