const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');
const xss = require('xss-clean');
const mongoSanitize = require('express-mongo-sanitize');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security

// Prevent MongoDB operator injection
app.use(mongoSanitize());

// Prevent XSS attacks
app.use(xss());

// Enable CORS with restrictive policies
app.use(cors({
  origin: process.env.CORS_ORIGIN || 'https://trusted-domain.com',
  credentials: true
}));

// Rate limiting to prevent brute force attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Body parsing with size limits to prevent abuse
app.use(express.json({
  limit: '10kb' // Limit JSON payload size
}));

app.use(express.urlencoded({
  extended: true,
  limit: '10kb' // Limit URL-encoded payload size
}));

// Request timeout to prevent DoS
app.use((req, res, next) => {
  req.setTimeout(30000, () => { // 30 second timeout
    res.status(408).json({
      error: 'Request timeout',
      message: 'The request took too long to process'
    });
  });
  next();
});

// Health check endpoint
app.get('/health', (req, res) => {
  // Validate query parameters if present
  const allowedParams = ['verbose', 'format'];
  const queryParams = Object.keys(req.query);

  const invalidParams = queryParams.filter(param => !allowedParams.includes(param));
  if (invalidParams.length > 0) {
    return res.status(400).json({
      error: 'Invalid query parameters',
      message: `The following parameters are not allowed: ${invalidParams.join(', ')}`
    });
  }

  const healthData = {
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  };

  // Add verbose data if requested
  if (req.query.verbose === 'true') {
    healthData.hostname = require('os').hostname();
    healthData.version = process.version;
  }

  res.json(healthData);
});

// Users endpoint with input validation
app.get('/users', (req, res, next) => {
  try {
    // Validate query parameters
    const { page, limit, sort } = req.query;

    // Default values
    let pageNum = 1;
    let limitNum = 10;
    let sortField = 'id';
    let sortDirection = 1;

    // Validate and sanitize page
    if (page !== undefined) {
      pageNum = parseInt(page, 10);
      if (isNaN(pageNum) || pageNum < 1) {
        return res.status(400).json({
          error: 'Invalid page parameter',
          message: 'Page must be a positive integer'
        });
      }
    }

    // Validate and sanitize limit
    if (limit !== undefined) {
      limitNum = parseInt(limit, 10);
      if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
        return res.status(400).json({
          error: 'Invalid limit parameter',
          message: 'Limit must be a positive integer between 1 and 100'
        });
      }
    }

    // Validate and sanitize sort
    if (sort !== undefined) {
      const sortMatch = sort.toString().match(/^([a-zA-Z]+)(:asc|:desc)?$/);
      if (!sortMatch) {
        return res.status(400).json({
          error: 'Invalid sort parameter',
          message: 'Sort format must be field:asc or field:desc'
        });
      }

      sortField = sortMatch[1];
      sortDirection = sortMatch[2] === ':desc' ? -1 : 1;

      // Only allow sorting by known fields
      const allowedSortFields = ['id', 'name', 'email'];
      if (!allowedSortFields.includes(sortField)) {
        return res.status(400).json({
          error: 'Invalid sort field',
          message: `Sorting by ${sortField} is not allowed`
        });
      }
    }

    // Mock users data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply sorting
    const sortedUsers = [...users].sort((a, b) => {
      if (a[sortField] < b[sortField]) return -1 * sortDirection;
      if (a[sortField] > b[sortField]) return 1 * sortDirection;
      return 0;
    });

    // Apply pagination
    const startIndex = (pageNum - 1) * limitNum;
    const paginatedUsers = sortedUsers.slice(startIndex, startIndex + limitNum);

    // Return paginated response
    res.json({
      data: paginatedUsers,
      pagination: {
        currentPage: pageNum,
        totalPages: Math.ceil(users.length / limitNum),
        totalItems: users.length,
        itemsPerPage: limitNum
      }
    });

  } catch (error) {
    // Pass errors to error handling middleware
    next(error);
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Not Found',
    message: `Cannot ${req.method} ${req.originalUrl}`
  });
});

// Global error handling middleware
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Prevent stack traces in production
  const isProduction = process.env.NODE_ENV === 'production';

  res.status(error.statusCode || 500).json({
    error: error.name || 'Internal Server Error',
    message: isProduction 
      ? 'Internal server error' 
      : error.message,
    // Include stack trace only in development
    ...(isProduction ? {} : { stack: error.stack })
  });
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (err) => {
  console.error('Unhandled Promise Rejection:', err);
  server.close(() => process.exit(1));
});

// Handle uncaught exceptions
process.on('uncaughtException', (err) => {
  console.error('Uncaught Exception:', err);
  server.close(() => process.exit(1));
});

module.exports = app;

