app.use(limiter);

// Request parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  // Clean query parameters - remove any potential malicious content
  if (req.query) {
    Object.keys(req.query).forEach(key => {
      // Basic sanitization - you might want to use dedicated sanitization libraries
      if (typeof req.query[key] === 'string') {
        req.query[key] = req.query[key].trim();
      }
    });
  }
  next();
};

// Health check with proper error handling
app.get('/health', validateQueryParams, (req, res) => {
  try {
    // Validate any query parameters if needed
    const allowedParams = ['verbose', 'detailed'];
    for (const param in req.query) {
      if (!allowedParams.includes(param)) {
        return res.status(400).json({
          error: `Invalid query parameter: ${param}`
        });
      }
    }

    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'An unexpected error occurred'
    });
  }
});

// Users endpoint with proper error handling and input validation
app.get('/users', validateQueryParams, (req, res) => {
  try {
    // Input validation
    const { limit, offset, search } = req.query;

    // Validate and sanitize query parameters
    let validatedLimit = 10;
    let validatedOffset = 0;
    let validatedSearch = null;

    if (limit) {
      const limitNum = parseInt(limit);
      if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
        return res.status(400).json({
          error: 'Invalid limit parameter. Must be a number between 1 and 100.'
        });
      }
      validatedLimit = limitNum;
    }

    if (offset) {
      const offsetNum = parseInt(offset);
      if (isNaN(offsetNum) || offsetNum < 0) {
        return res.status(400).json({
          error: 'Invalid offset parameter. Must be a non-negative number.'
        });
      }
      validatedOffset = offsetNum;
    }

    if (search) {
      if (typeof search !== 'string' || search.length > 50) {
        return res.status(400).json({
          error: 'Invalid search parameter. Must be a string with maximum 50 characters.'
        });
      }
      validatedSearch = search.trim();
    }

    // Mock data - in a real app, this would come from a database
    let users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply search filter if provided
    if (validatedSearch) {
      const searchLower = validatedSearch.toLowerCase();
      users = users.filter(user => 
        user.name.toLowerCase().includes(searchLower) || 
        user.email.toLowerCase().includes(searchLower)
      );
    }

    // Apply pagination
    const paginatedUsers = users.slice(validatedOffset, validatedOffset + validatedLimit);

    res.json({
      data: paginatedUsers,
      total: users.length,
      limit: validatedLimit,
      offset: validatedOffset
    });

  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'An unexpected error occurred'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
    message: `The requested endpoint ${req.method} ${req.url} does not exist.`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Determine status code based on error type
  const statusCode = error.statusCode || error.status || 500;

  res.status(statusCode).json({
    error: 'Internal server error',
    message: process.env.NODE_ENV === 'development' ? error.message : 'An unexpected error occurred'
  });
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM signal received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT signal received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

module.exports = app;

