{
  "name": "secure-express-app",
  "version": "1.0.0",
  "description": "A secure Express.js application with proper error handling and input validation",
  "main": "app.js",
  "scripts": {
    "start": "node app.js",
    "dev": "nodemon app.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "dotenv": "^16.0.3",
    "helmet": "^7.0.0",
    "cors": "^2.8.5",
    "express-rate-limit": "^6.7.0",
    "winston": "^3.8.2"
  },
  "devDependencies": {
    "nodemon": "^2.0.20"
  }
}

/**
 * Centralized error handling middleware
 * Implements security best practices for error handling
 */

const winston = require('winston');

// Configure logging with security in mind
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'user-service' },
  transports: [
    //
    // - Write to all logs with level `info` and below to `combined.log`
    // - Write all logs error (and below) to `error.log`.
    //
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
});

// If we're not in production, log to the console with a simple format
if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple()
  }));
}

/**
 * Error handling middleware
 * @param {Error} err - The error object
 * @param {Object} req - Express request object
 * @param {Object} res - Express response object
 * @param {Function} next - Express next function
 */
const errorHandler = (err, req, res, next) => {
  // Log the error details (with stack trace only in development)
  logger.error({
    message: err.message,
    stack: process.env.NODE_ENV === 'development' ? err.stack : undefined,
    path: req.path,
    method: req.method,
    ip: req.ip,
    userAgent: req.get('User-Agent')
  });

  // Determine status code
  const statusCode = res.statusCode !== 200 ? res.statusCode : 500;

  // Set status code
  res.status(statusCode);

  // Never expose sensitive error details in production
  res.json({
    success: false,
    message: process.env.NODE_ENV === 'production' ? 'Internal server error' : err.message,
    // Only include stack trace in development
    stack: process.env.NODE_ENV === 'development' ? err.stack : undefined
  });
};

module.exports = {
  errorHandler,
  logger
};

/**
 * Input validation middleware
 * Implements security best practices for input validation
 */

/**
 * Validates that an ID parameter is a positive integer
 * @param {Object} req - Express request object
 * @param {Object} res - Express response object
 * @param {Function} next - Express next function
 */
const validateIdParam = (req, res, next) => {
  const id = req.params.id;

  // Check if ID is provided
  if (!id) {
    return res.status(400).json({
      success: false,
      message: 'ID parameter is required'
    });
  }

  // Check if ID is a positive integer
  const idNumber = parseInt(id, 10);
  if (isNaN(idNumber) || idNumber <= 0 || !/^[0-9]+$/.test(id)) {
    return res.status(400).json({
      success: false,
      message: 'ID must be a positive integer'
    });
  }

  // Store validated ID as number
  req.params.id = idNumber;
  next();
};

/**
 * Sanitizes user input by removing potentially dangerous characters
 * @param {string} str - Input string to sanitize
 * @returns {string} Sanitized string
 */
const sanitizeInput = (str) => {
  if (typeof str !== 'string') return str;

  // Remove potentially dangerous characters
  // This is a basic example - consider using a dedicated library like DOMPurify for HTML
  return str
    .replace(/<script>/gi, '&lt;script&gt;')
    .replace(/<\/script>/gi, '&lt;/script&gt;')
    .replace(/javascript:/gi, 'javascript&amp;colon;')
    .replace(/vbscript:/gi, 'vbscript&amp;colon;')
    .replace(/onload=/gi, 'onload&amp;equals;')
    .trim();
};

/**
 * Basic validation middleware for user data
 * @param {Object} req - Express request object
 * @param {Object} res - Express response object
 * @param {Function} next - Express next function
 */
const validateUserData = (req, res, next) => {
  const { name, email } = req.body;

  // Validate name
  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return res.status(400).json({
      success: false,
      message: 'Name is required and must be a non-empty string'
    });
  }

  // Sanitize name
  req.body.name = sanitizeInput(name);

  // Validate and sanitize email
  if (!email || typeof email !== 'string') {
    return res.status(400).json({
      success: false,
      message: 'Email is required and must be a string'
    });
  }

  // Basic email format validation
  const emailRegex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;
  if (!emailRegex.test(email)) {
    return res.status(400).json({
      success: false,
      message: 'Email format is invalid'
    });
  }

  req.body.email = sanitizeInput(email).toLowerCase();

  next();
};

module.exports = {
  validateIdParam,
  validateUserData,
  sanitizeInput
};

