app.get('/health', (req, res) => {
  // Input validation
  const requiredFields = [];

  // Check for unexpected query parameters
  const allowedParams = [];
  const requestParams = Object.keys(req.query);

  for (const param of requestParams) {
    if (!allowedParams.includes(param)) {
      return res.status(400).json({
        error: 'Invalid parameter',
        message: `Parameter '${param}' is not supported`
      });
    }
  }

  res.json({ 
    status: 'ok', 
    timestamp: new Date().toISOString(),
    environment: process.env.NODE_ENV || 'development'
  });
});

// Users endpoint
app.get('/users', (req, res) => {
  try {
    // Input validation and filtering
    const { page = 1, limit = 10, sort } = req.query;

    // Validate query parameters
    const pageNum = parseInt(page);
    const limitNum = parseInt(limit);

    if (isNaN(pageNum) || pageNum < 1) {
      return res.status(400).json({
        error: 'Invalid page parameter',
        message: 'Page must be a positive integer'
      });
    }

    if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
      return res.status(400).json({
        error: 'Invalid limit parameter',
        message: 'Limit must be a positive integer between 1 and 100'
      });
    }

    if (sort && !['name', 'email', 'id'].includes(sort)) {
      return res.status(400).json({
        error: 'Invalid sort parameter',
        message: 'Sort must be one of: name, email, id'
      });
    }

    // Sample user data (in real app, this would come from a database)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Simple pagination
    const startIndex = (pageNum - 1) * limitNum;
    const endIndex = startIndex + limitNum;
    let results = users.slice(startIndex, endIndex);

    // Simple sorting
    if (sort) {
      results.sort((a, b) => {
        if (a[sort] < b[sort]) return -1;
        if (a[sort] > b[sort]) return 1;
        return 0;
      });
    }

    res.json({
      page: pageNum,
      limit: limitNum,
      total: users.length,
      totalPages: Math.ceil(users.length / limitNum),
      data: results
    });

  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'An unexpected error occurred'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Not found',
    message: `Route ${req.method} ${req.url} not found`
  });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Uncaught error:', err);

  // Handle specific error types
  if (err.name === 'ValidationError') {
    return res.status(400).json({
      error: 'Validation error',
      message: err.message
    });
  }

  // For any other errors
  res.status(500).json({
    error: 'Internal server error',
    message: 'An unexpected error occurred'
  });
