const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const xss = require('xss-clean');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet({
  contentSecurityPolicy: false, // Need to configure properly for your needs
}));

// Rate limiting to prevent brute force attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Parse JSON bodies
app.use(express.json({
  limit: '10kb' // Limit request body size
}));

// Data sanitization against XSS
app.use(xss());

// Enable CORS with restrictions
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || '*', // Configure for production
  credentials: true
}));

// Request logging middleware
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.path}`);
  next();
});

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    // Validate any query parameters if present
    const allowedParams = ['format', 'detailed'];
    const queryParams = Object.keys(req.query);

    for (const param of queryParams) {
      if (!allowedParams.includes(param)) {
        return res.status(400).json({
          error: `Invalid query parameter: ${param}`
        });
      }
    }

    const healthData = {
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    };

    // Optional detailed response
    if (req.query.detailed === 'true') {
      healthData.nodeVersion = process.version;
      healthData.memoryUsage = process.memoryUsage();
    }

    res.json(healthData);
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      error: 'Internal server error'
    });
  }
});

// Users endpoint
app.get('/users', (req, res) => {
  try {
    // Validate and sanitize query parameters
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;

    // Input validation
    if (page < 1 || limit < 1 || limit > 100) {
      return res.status(400).json({
        error: 'Invalid pagination parameters'
      });
    }

    // Simulated user data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // In a real app, you'd implement proper pagination here

    res.json({
      data: users,
      pagination: {
        page,
        limit,
        total: users.length,
        pages: Math.ceil(users.length / limit)
      }
    });

  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.method} ${req.path} not found`
  });
});

// Global error handling middleware
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Hide detailed error messages in production
  const isProduction = process.env.NODE_ENV === 'production';

  res.status(error.statusCode || 500).json({
    error: isProduction ? 'Internal server error' : error.message
  });
});

// Graceful shutdown
process.on('unhandledRejection', (err) => {
  console.error('Unhandled rejection:', err);
  process.exit(1);
});

process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  process.exit(1);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

module.exports = app;
module.exports.server = server;

