// Global error handling middleware
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

  res.status(error.statusCode || 500).json({
    error: error.message || 'Internal server error',
    timestamp: new Date().toISOString()
  });
});

// Handle 404 routes
